INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2084, 209669, 5, 2283, '远行', '当我为你办了所有出国的手续时，觉得好难过也好兴奋哦！你终于可以远行了，去寻找你所追求的梦想。而我呢，静静地站在这里，望着你渐渐远去的背影，默数着过去所有快乐的时光，希望能够有点安抚我万般挣扎的舍不得。今天的天很好，天蓝蓝的，水柔柔的，周围的花儿都在为了我们的离别而开放着。偶尔有几只小鸟从头上悄悄地飞过，我知道他们也是在为你导航，希望你能远行顺利些，并且早点归来。请你记得海边的我，在这里等你，请记得你的开不了口，请记得我们流星雨的约定，请记得那杯永远为你而热的珍珠奶茶，请记得要安静地离开，别打搅我美丽的梦~~', '当我为你办了所有出国的手续时，觉得好难过也好兴奋哦！你终于可以远行了，去寻找你所追求的梦想。而我呢，静静地站在这里，望着你渐渐远去的背影，默数着过去所有快乐的时光，希望能够有点安抚我万般挣扎的舍不得。今天的天很好，天蓝蓝的，水柔柔的，周围的花儿都在为了我们的离别而开放着。偶尔有几只小鸟从头上悄悄地飞过，我知道他们也是在为你导航，希望你能远行顺利些，并且早点归来。请你记得海边的我，在这里等你，请记得你的开不了口，请记得我们流星雨的约定，请记得那杯永远为你而热的珍珠奶茶，请记得要安静地离开，别打搅我美丽的梦~~', '享恋^(oo)^', '2003-07-25 13:16:00', 2, '20030819194700_bbsid_209669_board_5_f5a74d4224.html', '20030819194700');
